mod maxmin_chunker;
mod voyage_api;

use anyhow::{Result, Context};
use std::env;
use std::path::Path;
use maxmin_chunker::{MaxMinChunker, ChunkerConfig, visualize_chunks};

#[tokio::main]
async fn main() -> Result<()> {
    // Load .env file if it exists
    dotenv::dotenv().ok();

    let args: Vec<String> = env::args().collect();

    // Parse command line arguments
    if args.len() < 2 {
        eprintln!("Usage: {} <text_file> [options]", args[0]);
        eprintln!("\nOptions:");
        eprintln!("  --api-key <key>            Voyage API key (or set VOYAGE_API_KEY env var)");
        eprintln!("  --fixed-threshold <float>  Fixed similarity threshold (default: 0.6)");
        eprintln!("  --c <float>                Coefficient for threshold adjustment (default: 0.9)");
        eprintln!("  --init-constant <float>    Initial constant for single-sentence clusters (default: 1.5)");
        eprintln!("\nExamples:");
        eprintln!("  {} sample.txt", args[0]);
        eprintln!("  {} sample.txt --api-key YOUR_KEY", args[0]);
        eprintln!("  {} sample.txt --fixed-threshold 0.5 --c 0.8", args[0]);
        std::process::exit(1);
    }

    let file_path = &args[1];

    // Get API key from environment or command line
    let mut api_key = env::var("VOYAGE_API_KEY").ok();
    let mut fixed_threshold = 0.6;
    let mut c = 0.9;
    let mut init_constant = 1.5;

    // Parse optional arguments
    let mut i = 2;
    while i < args.len() {
        match args[i].as_str() {
            "--api-key" => {
                if i + 1 < args.len() {
                    api_key = Some(args[i + 1].clone());
                    i += 2;
                } else {
                    eprintln!("Error: --api-key requires a value");
                    std::process::exit(1);
                }
            }
            "--fixed-threshold" => {
                if i + 1 < args.len() {
                    fixed_threshold = args[i + 1].parse()
                        .context("Invalid fixed_threshold value")?;
                    i += 2;
                } else {
                    eprintln!("Error: --fixed-threshold requires a value");
                    std::process::exit(1);
                }
            }
            "--c" => {
                if i + 1 < args.len() {
                    c = args[i + 1].parse()
                        .context("Invalid c coefficient value")?;
                    i += 2;
                } else {
                    eprintln!("Error: --c requires a value");
                    std::process::exit(1);
                }
            }
            "--init-constant" => {
                if i + 1 < args.len() {
                    init_constant = args[i + 1].parse()
                        .context("Invalid init_constant value")?;
                    i += 2;
                } else {
                    eprintln!("Error: --init-constant requires a value");
                    std::process::exit(1);
                }
            }
            _ => {
                eprintln!("Unknown argument: {}", args[i]);
                std::process::exit(1);
            }
        }
    }

    // Ensure API key is available
    let api_key = api_key.context("VOYAGE_API_KEY not found. Set it via environment variable or --api-key argument")?;

    // Read the input file
    let text = std::fs::read_to_string(file_path)
        .with_context(|| format!("Failed to read file: {}", file_path))?;

    // Create chunker configuration
    let config = ChunkerConfig {
        api_key,
        fixed_threshold,
        c,
        init_constant,
    };

    println!("Configuration:");
    println!("  Fixed threshold: {}", config.fixed_threshold);
    println!("  Coefficient (c): {}", config.c);
    println!("  Initial constant: {}", config.init_constant);
    println!("  Using Voyage AI API (voyage-context-3)\n");

    // Create the chunker
    let chunker = MaxMinChunker::new(config);

    // Process the text
    println!("Processing text...");
    let result = chunker.chunk_text(&text).await?;

    // Display results
    println!("\n=== Chunking Results ===\n");
    println!("Total chunks: {}", result.chunks.len());
    println!("Total tokens used: {} (estimated)", result.total_tokens);
    println!("\n=== Chunks ===\n");

    for (i, chunk) in result.chunks.iter().enumerate() {
        println!("Chunk {} (sentences {}-{}):", 
                 i + 1, 
                 chunk.start_idx + 1, 
                 chunk.end_idx + 1);
        println!("Adaptive threshold: {:.3}", chunk.adaptive_threshold);
        println!("Content:");
        println!("{}", chunk.text);
        println!("\n{}", "-".repeat(80));
        println!();
    }

    // Visualize the chunks
    println!("\n=== Chunk Visualization ===\n");
    visualize_chunks(&result.chunks);

    Ok(())
}

